#!/usr/bin/env node
// scaffold-day3.mjs - Day 3: Standup + CEO Brief + operational visibility
//
// Adds:
//   1. Daily standup ritual at 09:30 company time (6 directors + Eleanor + Ayaka)
//   2. CEO Brief at 10:00 company time (Eleanor synthesizes standup, posts to #ceo-brief, DMs CEO)
//   3. CEO sentinel agent (paused, never run, exists so DMs have a target)
//   4. Dashboard 'Brief' tab as the new default tab
//   5. 'Today' operational visibility strip in the dashboard header
//
// Touches the database. After running this scaffold:
//   1. Run apps/orchestrator/supabase/migrations/0004_day3.sql in Supabase SQL editor
//   2. Run: pnpm --filter @headcount/orchestrator exec tsx src/seed/seed-ceo.ts
//   3. Reset clock SQL (see end-of-output instructions)
//   4. Restart orchestrator (Ctrl+C, pnpm orchestrator:dev)
//   5. Restart dashboard (Ctrl+C, pnpm dashboard:dev)

import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';

const ROOT = process.cwd();

function writeFile(relPath, base64Content) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  const bytes = Buffer.from(base64Content, 'base64');
  writeFileSync(full, bytes);
  console.log('  + ' + relPath);
}

console.log('');
console.log('Day 3 scaffold - Standup + CEO Brief + operational visibility');
console.log('Writing to: ' + ROOT);
console.log('');
console.log('Writing 6 files...');
writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/rituals/ceo-brief.ts', '');
writeFile('apps/orchestrator/src/rituals/standup.ts', '');
writeFile('apps/orchestrator/src/seed/seed-ceo.ts', '');
writeFile('apps/orchestrator/src/world/tick.ts', '');
writeFile('apps/orchestrator/supabase/migrations/0004_day3.sql', '');

console.log('');
console.log('Done. Wrote 6 files.');
console.log('');
console.log('NEXT STEPS - do these in order:');
